import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirRouteNames } from '../../routeNames';
import { hirAccountActions } from '../actions';
import { hirAccountStrings } from '../config';
import { HIRPaymentList } from '../HIRPaymentList';
import { Typography } from '@material-ui/core';
import { hirMonthSelections as monthSelections, headerActions, headerStrings, breadCrumbActions, history } from "../../utils";


const style = theme => ({
    root: {
    },
    info : {
        display : "flex",
        marginBottom : 10,
    },
    date : {
        color : theme.colors.secondary,
    },
    total : {
        display : "flex", 
        justifyContent : "center", 
        alignItems : "center",
        color : "white",
        backgroundColor : theme.colors.primary1,
        borderRadius : 20,
        fontSize : 14,
        fontWeight : "bold",
        padding : 10
    }
})
class _HIRViewPaymentDetail extends Component {
    constructor(props) {
        super(props);
        console.log(props);
        this.locationState = props.location.state;
        const {type} = props.location.state;
        if(type === "revenue")
            this.configRevenueCategory(props);
        else this.configUserCategory(props);
    }
    componentDidMount() {
        this.getPayments();
    }
    configUserCategory(props){
        const {dispatch, location} = props;
        const {type, user, userId, monthOnlyView, date} = location.state;
        //visit this page directly will send you back to account
        if(!userId && !type) history.replace(hirRouteNames.account);
        const crumbOption = [
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Accounts", pathname : hirRouteNames.account}
        ];
        const headerOption = {
            [headerStrings.backButtonAction] : ()=>history.replace(hirRouteNames.account)
        }
        if(user && user.myProfile){
            const {myProfile} = user;
            const userName = myProfile.lastName + ", " + myProfile.firstName;
            this.detailName = userName;
            crumbOption.push({name : userName, pathname : ""})
            headerOption[headerStrings.headerTitle] = "PAYMENTS ["+userName+"]";
        }else{
            headerOption[headerStrings.headerTitle] = "PAYMENTS";
        }
        headerActions(headerOption)(dispatch);
        breadCrumbActions.setBreadCrumb(crumbOption)(dispatch);
    }
    configRevenueCategory(props){
        const {dispatch, location} = props;
        const {type, name, revenueCats} = location.state;
        if(!name && !type) history.replace(hirRouteNames.account);
        const crumbOption = [
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Accounts", pathname : hirRouteNames.account}
        ];
        const headerOption = {
            [headerStrings.backButtonAction] : ()=>history.replace(hirRouteNames.account)
        }
        if(revenueCats){
            const option = revenueCats.find(item=>item.name===name);
            if(option){
                crumbOption.push({name : option.value, pathname : ""})
                headerOption[headerStrings.headerTitle] = "PAYMENTS ["+option.value+"]";
                this.detailName = option.value;
            }else{
                headerOption[headerStrings.headerTitle] = "PAYMENTS";
            }
        }
        headerActions(headerOption)(dispatch);
        breadCrumbActions.setBreadCrumb(crumbOption)(dispatch);
    }
    getPayments(){
        const {type, name, userId, date : searchDate, monthOnlyView} = this.locationState;
        const {dispatch} = this.props;
        try{
            const date = new Date(searchDate);
            if(type === "revenue"){
                hirAccountActions.getPaymentByRevenueTypeAndDate(
                    name, 
                    date.getFullYear(),
                    date.getMonth() + 1,
                    monthOnlyView ? null : date.getDate(),
                    (done, result) => console.log(result, done)
                )(dispatch);
            }else{
                hirAccountActions.getPaymentByUserIdAndDate(
                    userId, 
                    date.getFullYear(),
                    date.getMonth() + 1,
                    monthOnlyView ? null : date.getDate(),
                    (done, result) => console.log(result, done)
                )(dispatch);
            }
        }catch(message){
            console.error(message);
        }
    }
    render() {
        let {
            classes,
            [hirAccountStrings.viewDetailPayments] : payments
        } = this.props;
        let total = 0;
        if(payments){
            for (let i = 0; i < payments.length; i++) {
                const element = payments[i];
                if(!isNaN(parseInt(element.amount))) {
                    total += element.amount;
                }
            }
            payments = [...payments, {lastLine : true, total}]
        }
        const date = new Date(this.locationState.date);
        return (
            <div className={classes.root}>
                <div className={classes.info}>
                    <Typography paragraph className={classes.header}>
                        Revenue 
                        {this.locationState.type === "revenue" ? " from " : " by "}
                        {this.detailName}
                        {this.locationState.monthOnlyView ? " for month of " : " for "}
                        {this.locationState.monthOnlyView ? <strong className={classes.date}>{monthSelections.find(item=>item.value === date.getMonth() + 1).name +
                            "("+date.getFullYear()+")"}</strong> 
                            :
                            <strong className={classes.date}>{date.toLocaleDateString()}</strong>
                        }
                    </Typography>
                    <div style={{display : "flex", flexGrow : 1}}/>
                    <div className={classes.total}>
                        Total : N{Number(total).toLocaleString()}
                    </div>
                </div>
                <HIRPaymentList
                    tableProps={{
                        data : payments && payments.map(item=>{
                            return { 
                                    ...item, 
                                    name : item.patient && item.patient[0] ? 
                                        item.patient[0].myProfile.lastName + ", " + 
                                        item.patient[0].myProfile.firstName 
                                        : null
                            }
                        })
                    }}
                    />
            </div>
        );
    }
}


_HIRViewPaymentDetail.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirAccountReducer}) => ({
    [hirAccountStrings.viewDetailPayments] : hirAccountReducer[hirAccountStrings.viewDetailPayments]
})


export const HIRViewPaymentDetail = connect(mapStateToProps)(withStyles(style)(_HIRViewPaymentDetail));
export {HIRViewPaymentDetail as default}